import{_ as t,o as a,c as i,a2 as s}from"./chunks/framework.D36jym0Z.js";const g=JSON.parse('{"title":"Stable Prefix","description":"","frontmatter":{},"headers":[],"relativePath":"plugin-catalog/tokenpilot/stable-prefix.md","filePath":"plugin-catalog/tokenpilot/stable-prefix.md","lastUpdated":1784542960000}'),n={name:"plugin-catalog/tokenpilot/stable-prefix.md"};function l(o,e,r,h,p,c){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="stable-prefix" tabindex="-1">Stable Prefix <a class="header-anchor" href="#stable-prefix" aria-label="Permalink to &quot;Stable Prefix&quot;">​</a></h1><p>The stable prefix is TokenPilot&#39;s primary mechanism for improving <strong>cache hit rates</strong> in long-running agent sessions.</p><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>Every turn in an agent session, the full conversation history is sent to the model. Most of that context is <strong>identical</strong> from turn to turn — system prompts, tool definitions, earlier messages.</p><p>However, even tiny differences in the prefix can cause a <strong>cache miss</strong>, forcing the model to recompute everything. Without stabilization, dynamic content (timestamps, session IDs, variable instructions) gets interleaved with static content, breaking the cache.</p><h2 id="how-stable-prefix-works" tabindex="-1">How Stable Prefix Works <a class="header-anchor" href="#how-stable-prefix-works" aria-label="Permalink to &quot;How Stable Prefix Works&quot;">​</a></h2><p>TokenPilot separates context into two parts:</p><ol><li><strong>Stable prefix</strong>: Everything that doesn&#39;t change between turns (system prompts, tool schemas, static instructions)</li><li><strong>Dynamic suffix</strong>: What changes each turn (new messages, tool outputs, variable content)</li></ol><p>By keeping the stable prefix identical across turns, the model API can reuse the cached computation. Only the dynamic suffix is recomputed.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Turn N:   [ Stable Prefix ] [ Dynamic Content N ]</span></span>
<span class="line"><span>Turn N+1: [ Stable Prefix ] [ Dynamic Content N+1 ]</span></span>
<span class="line"><span>                ↑</span></span>
<span class="line"><span>          Cache hits here — no recomputation</span></span></code></pre></div><h2 id="stabilizer-target" tabindex="-1">Stabilizer Target <a class="header-anchor" href="#stabilizer-target" aria-label="Permalink to &quot;Stabilizer Target&quot;">​</a></h2><p>The <code>stabilizer target</code> setting controls where dynamic content is attached:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Target</th><th style="text-align:left;">Behavior</th><th style="text-align:left;">Cache Efficiency</th></tr></thead><tbody><tr><td style="text-align:left;"><code>developer</code></td><td style="text-align:left;">Dynamic content goes in developer messages</td><td style="text-align:left;">Good</td></tr><tr><td style="text-align:left;"><code>user</code></td><td style="text-align:left;">Dynamic content goes in user messages</td><td style="text-align:left;">Best</td></tr></tbody></table><p>The <code>user</code> target (used in aggressive mode) puts dynamic content further from the model&#39;s expected structure, maximizing cache reuse. The <code>developer</code> target (used in conservative and normal modes) keeps dynamic content closer to where it logically belongs.</p><h2 id="visual-feedback" tabindex="-1">Visual Feedback <a class="header-anchor" href="#visual-feedback" aria-label="Permalink to &quot;Visual Feedback&quot;">​</a></h2><p>Open the visual inspector to see your stable prefix in action:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lightmem2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> visual</span></span></code></pre></div><p>The stabilizer view shows:</p><ul><li>Total context size</li><li>Stable portion vs. dynamic portion</li><li>Cache hit/miss ratio</li><li>Per-turn stability metrics</li></ul><h2 id="tuning" tabindex="-1">Tuning <a class="header-anchor" href="#tuning" aria-label="Permalink to &quot;Tuning&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Toggle stabilizer</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lightmem2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stabilizer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> on</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lightmem2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stabilizer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> off</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Change target</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lightmem2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stabilizer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> target</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> developer</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lightmem2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stabilizer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> target</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user</span></span></code></pre></div><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/LightMem2/plugin-catalog/tokenpilot/context-reduction">Context Reduction</a> — trimming tool output</li><li><a href="/LightMem2/plugin-catalog/tokenpilot/context-eviction">Context Eviction</a> — pruning old context</li><li><a href="/LightMem2/plugin-catalog/tokenpilot/reports-and-visuals">Reports and Visuals</a> — see the effect</li></ul>`,23)])])}const u=t(n,[["render",l]]);export{g as __pageData,u as default};
